import type { ICamera, Point2, Point3 } from '../../types';
import type DisplayArea from '../../types/displayArea';
import type { ViewPresentationSelector } from '../../types/IViewport';
import type ViewportType from '../../enums/ViewportType';
export type ProjectionScale = {
    kind: 'fit';
    value: number;
} | {
    kind: 'fitWidth';
    value: number;
} | {
    kind: 'fitHeight';
    value: number;
} | {
    kind: 'displayArea';
    value: number;
    area: DisplayArea;
} | {
    kind: 'nativePixel';
    pixelsPerCanvasPixel: number;
} | {
    kind: 'physical';
    mmPerCanvasPixel: number;
} | {
    kind: 'signal';
    samplesPerCanvasPixel: number;
    valueUnitsPerCanvasPixel: number;
};
export type ProjectionPosition = {
    kind: 'anchor';
    worldPoint?: Point3;
    canvasPoint: Point2;
} | {
    kind: 'imagePoint';
    imagePoint: Point2;
    canvasPoint: Point2;
} | {
    kind: 'mediaPoint';
    mediaPoint: Point2;
    canvasPoint: Point2;
} | {
    kind: 'signalPoint';
    sampleIndex: number;
    value: number;
    channelIndex: number;
    canvasPoint: Point2;
} | {
    kind: 'focalPoint';
    worldPoint: Point3;
};
export interface ProjectionPresentation<TDisplayArea = DisplayArea> {
    rotation?: number;
    displayArea?: TDisplayArea;
    zoom?: number;
    pan?: Point2;
    scale?: ProjectionScale;
    position?: ProjectionPosition;
    flipHorizontal?: boolean;
    flipVertical?: boolean;
}
export interface ProjectionSpaces {
    canvas?: boolean;
    world?: boolean;
    image?: boolean;
    renderer?: boolean;
}
export interface ProjectionTransforms {
    canvasToWorld?(point: Point2): Point3;
    worldToCanvas?(point: Point3): Point2;
}
export interface ProjectionSnapshot<TViewState = unknown, TProjectionPresentation extends ProjectionPresentation<unknown> = ProjectionPresentation> {
    kind: string;
    adapterId: string;
    viewportType?: ViewportType | string;
    dataId?: string;
    frameOfReferenceUID?: string;
    spaces: ProjectionSpaces;
    transforms?: ProjectionTransforms;
    presentation: TProjectionPresentation;
    rendererCamera?: ICamera<unknown>;
    viewState?: TViewState;
}
export interface ProjectionRequest<TViewport = unknown> {
    viewport: TViewport;
    kind?: string;
    dataId?: string;
    viewportType?: ViewportType | string;
    selector?: ViewPresentationSelector;
}
export interface ProjectionWriteOptions {
    anchorCanvas?: Point2;
    preserveDisplayArea?: boolean;
}
export interface ViewportProjectionAdapter<TViewState = unknown, TPresentation = unknown, TSnapshot extends ProjectionSnapshot<TViewState, ProjectionPresentation<unknown>> = ProjectionSnapshot<TViewState>> {
    id: string;
    viewportTypes: Array<ViewportType | string>;
    getSnapshot(request: ProjectionRequest): TSnapshot | undefined;
    getPresentation(snapshot: TSnapshot, selector?: ViewPresentationSelector): TPresentation;
    withPresentation(snapshot: TSnapshot, presentation: Partial<TPresentation>, options?: ProjectionWriteOptions): TViewState;
    applyToRenderer?(snapshot: TSnapshot, target: unknown): void;
}
